CREATE TABLE IF NOT EXISTS public.oauth_authorizations (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    oauth_app_id UUID NOT NULL REFERENCES public.oauth_apps(id) ON DELETE CASCADE,
