CREATE POLICY "Allow authenticated users to upload blog images"
    ON storage.objects
    AS PERMISSIVE
    FOR INSERT
    TO authenticated
    WITH CHECK (
        bucket_id = 'blog_images'::text
        AND auth.role() = 'authenticated'::text
        AND auth.uid() = owner
    );

DROP POLICY IF EXISTS "Allow read access to blog images" ON storage.objects;
