-- Module: user-auth, File: 401_20260401_functions.sql
-- ---------------------------
-- MODULE NAME: User Auth
-- MODULE DATE: 20260401
-- MODULE SCOPE: Functions
-- ---------------------------



-- Sync auth.users -> public.users: OAuth and email-confirm flows set email_confirmed_at in auth;
-- public.users.is_email_verified must match so password sign-in and app policy stay consistent.
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = ''
AS $$
BEGIN
  INSERT INTO public.users (id, auth_id, email, full_name, is_email_verified)
  VALUES (
    new.id,
    new.id,
    new.email,
    COALESCE((new.raw_user_meta_data->>'full_name')::text, new.email),
    (new.email_confirmed_at IS NOT NULL)
  );
  RETURN new;
END;
$$;

-- Existing rows: align with Supabase auth confirmation (fixes OAuth users created before this change).
UPDATE public.users u
SET is_email_verified = true,
    updated_at = NOW()
FROM auth.users a
WHERE u.auth_id = a.id
  AND a.email_confirmed_at IS NOT NULL
  AND COALESCE(u.is_email_verified, false) = false;


-- Module: organization, File: 401_20260406_functions.sql
-- ---------------------------
-- MODULE NAME: organization
-- MODULE DATE: 20260406
-- MODULE SCOPE: Functions
-- ---------------------------
-- Membership helpers for RLS: inline EXISTS subqueries on user_organizations
-- from policies on the same table (or nested checks) caused infinite recursion (42P17).
-- These SECURITY DEFINER functions read membership with owner privileges so RLS does not
-- re-enter the same policy.



CREATE OR REPLACE FUNCTION public.is_active_member_of_org(p_organization_id uuid, p_auth_id uuid)
RETURNS boolean
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
STABLE
AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.user_organizations uo
    JOIN public.users u ON u.id = uo.user_id
    WHERE uo.organization_id = p_organization_id
      AND u.auth_id = p_auth_id
      AND uo.disabled = FALSE
  );
$$;

CREATE OR REPLACE FUNCTION public.is_active_admin_or_superadmin_of_org(p_organization_id uuid, p_auth_id uuid)
RETURNS boolean
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
STABLE
AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.user_organizations uo
    JOIN public.users u ON u.id = uo.user_id
    WHERE uo.organization_id = p_organization_id
      AND u.auth_id = p_auth_id
      AND uo.disabled = FALSE
      AND uo.role IN ('admin', 'superadmin')
  );
$$;

CREATE OR REPLACE FUNCTION public.is_active_superadmin_of_org(p_organization_id uuid, p_auth_id uuid)
RETURNS boolean
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
STABLE
AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.user_organizations uo
    JOIN public.users u ON u.id = uo.user_id
    WHERE uo.organization_id = p_organization_id
      AND u.auth_id = p_auth_id
      AND uo.disabled = FALSE
      AND uo.role = 'superadmin'
  );
$$;

GRANT EXECUTE ON FUNCTION public.is_active_member_of_org(uuid, uuid) TO authenticated;
GRANT EXECUTE ON FUNCTION public.is_active_member_of_org(uuid, uuid) TO service_role;
GRANT EXECUTE ON FUNCTION public.is_active_admin_or_superadmin_of_org(uuid, uuid) TO authenticated;
GRANT EXECUTE ON FUNCTION public.is_active_admin_or_superadmin_of_org(uuid, uuid) TO service_role;
GRANT EXECUTE ON FUNCTION public.is_active_superadmin_of_org(uuid, uuid) TO authenticated;
GRANT EXECUTE ON FUNCTION public.is_active_superadmin_of_org(uuid, uuid) TO service_role;

COMMENT ON FUNCTION public.is_active_member_of_org(uuid, uuid) IS 'RLS helper: non-disabled membership in organization (bypasses RLS inside).';
COMMENT ON FUNCTION public.is_active_admin_or_superadmin_of_org(uuid, uuid) IS 'RLS helper: admin or superadmin membership (bypasses RLS inside).';
COMMENT ON FUNCTION public.is_active_superadmin_of_org(uuid, uuid) IS 'RLS helper: superadmin membership (bypasses RLS inside).';

-- ---------------------------
-- RLS: organizations (replace policies to use helpers)
-- ---------------------------

DROP POLICY IF EXISTS "Members can view organization" ON public.organizations;
CREATE POLICY "Members can view organization"
ON public.organizations
AS PERMISSIVE
FOR SELECT
TO authenticated
USING (public.is_active_member_of_org(organizations.id, auth.uid()));

DROP POLICY IF EXISTS "Admins can update organization" ON public.organizations;
CREATE POLICY "Admins can update organization"
ON public.organizations
AS PERMISSIVE
FOR UPDATE
TO authenticated
USING (public.is_active_admin_or_superadmin_of_org(organizations.id, auth.uid()))
WITH CHECK (public.is_active_admin_or_superadmin_of_org(organizations.id, auth.uid()));

DROP POLICY IF EXISTS "Superadmin can delete organization" ON public.organizations;
CREATE POLICY "Superadmin can delete organization"
ON public.organizations
AS PERMISSIVE
FOR DELETE
TO authenticated
USING (public.is_active_superadmin_of_org(organizations.id, auth.uid()));

-- ---------------------------
-- RLS: user_organizations (replace policies to use helpers)
-- ---------------------------

DROP POLICY IF EXISTS "Members can view user_organizations" ON public.user_organizations;
CREATE POLICY "Members can view user_organizations"
ON public.user_organizations
AS PERMISSIVE
FOR SELECT
TO authenticated
USING (public.is_active_member_of_org(user_organizations.organization_id, auth.uid()));

DROP POLICY IF EXISTS "Admins can add team member" ON public.user_organizations;
CREATE POLICY "Admins can add team member"
ON public.user_organizations
AS PERMISSIVE
FOR INSERT
TO authenticated
WITH CHECK (public.is_active_admin_or_superadmin_of_org(user_organizations.organization_id, auth.uid()));

DROP POLICY IF EXISTS "Admins can update membership" ON public.user_organizations;
CREATE POLICY "Admins can update membership"
ON public.user_organizations
AS PERMISSIVE
FOR UPDATE
TO authenticated
USING (public.is_active_admin_or_superadmin_of_org(user_organizations.organization_id, auth.uid()))
WITH CHECK (public.is_active_admin_or_superadmin_of_org(user_organizations.organization_id, auth.uid()));

DROP POLICY IF EXISTS "Admins or self can delete membership" ON public.user_organizations;
CREATE POLICY "Admins or self can delete membership"
ON public.user_organizations
AS PERMISSIVE
FOR DELETE
TO authenticated
USING (
    EXISTS (
        SELECT 1 FROM public.users u
        WHERE u.id = user_organizations.user_id AND u.auth_id = auth.uid()
    )
    OR public.is_active_admin_or_superadmin_of_org(user_organizations.organization_id, auth.uid())
);

-- ---------------------------
-- RLS: organization_invites (admin insert uses helper)
-- ---------------------------

DROP POLICY IF EXISTS "Admins can create invite" ON public.organization_invites;
CREATE POLICY "Admins can create invite"
ON public.organization_invites
AS PERMISSIVE
FOR INSERT
TO authenticated
WITH CHECK (public.is_active_admin_or_superadmin_of_org(organization_invites.organization_id, auth.uid()));

-- ---------------------------
-- Backend RPC helpers (API performance)
-- ---------------------------

-- Fast group-by member counts for organization lists.
-- Used by backend `OrganizationRepository.getMemberCounts` to avoid fetching all rows and counting in JS.
CREATE OR REPLACE FUNCTION public.internal_get_org_member_counts(p_org_ids uuid[])
RETURNS TABLE (organization_id uuid, member_count integer)
LANGUAGE sql
SECURITY DEFINER
STABLE
AS $$
  SELECT
    uo.organization_id,
    COUNT(*)::integer AS member_count
  FROM public.user_organizations uo
  WHERE uo.organization_id = ANY(p_org_ids)
    AND uo.disabled = false
  GROUP BY uo.organization_id;
$$;

-- One-shot team list (membership + email/full_name).
-- Used by backend `OrganizationRepository.getTeam` to avoid two sequential queries.
CREATE OR REPLACE FUNCTION public.internal_get_org_team_members(p_organization_id uuid)
RETURNS TABLE (
  id uuid,
  user_id uuid,
  organization_id uuid,
  role text,
  disabled boolean,
  created_at timestamptz,
  updated_at timestamptz,
  email text,
  full_name text
)
LANGUAGE sql
SECURITY DEFINER
STABLE
AS $$
  SELECT
    uo.id,
    uo.user_id,
    uo.organization_id,
    uo.role,
    uo.disabled,
    uo.created_at,
    uo.updated_at,
    u.email,
    u.full_name
  FROM public.user_organizations uo
  JOIN public.users u ON u.id = uo.user_id
  WHERE uo.organization_id = p_organization_id;
$$;


-- Module: customer, File: 401_20260412_functions.sql
-- ---------------------------
-- MODULE NAME: customer
-- MODULE DATE: 20260412
-- MODULE SCOPE: Functions
-- ---------------------------
-- Canonical `internal_list_integrations_by_org`: joins `integration_customers` for list payloads.
-- MODULE_ORDER runs this module before integration in the same tier; the integration module
-- must not ship a second definition with a different RETURNS TABLE shape (PostgreSQL 42P13).
-- Existing DBs may still have the older RETURNS TABLE; `CREATE OR REPLACE` cannot change OUT
-- types (42P13), so drop first when upgrading.



DROP FUNCTION IF EXISTS public.internal_list_integrations_by_org(uuid);

CREATE OR REPLACE FUNCTION public.internal_list_integrations_by_org(p_organization_id uuid)
RETURNS TABLE (
    id uuid,
    organization_id uuid,
    internal_id text,
    name text,
    picture text,
    provider_identifier text,
    type text,
    disabled boolean,
    in_between_steps boolean,
    refresh_needed boolean,
    posting_times text,
    additional_settings text,
    profile text,
    created_at timestamptz,
    updated_at timestamptz,
    customer_id uuid,
    customer_name text
)
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
STABLE
AS $$
    SELECT
        i.id,
        i.organization_id,
        i.internal_id,
        i.name,
        i.picture,
        i.provider_identifier,
        i.type,
        i.disabled,
        i.in_between_steps,
        i.refresh_needed,
        i.posting_times,
        i.additional_settings,
        i.profile,
        i.created_at,
        i.updated_at,
        i.customer_id,
        ic.name AS customer_name
    FROM public.integrations i
    LEFT JOIN public.integration_customers ic
        ON ic.id = i.customer_id
        AND ic.organization_id = i.organization_id
    WHERE i.organization_id = p_organization_id
      AND i.deleted_at IS NULL
    ORDER BY i.created_at ASC;
$$;

REVOKE ALL ON FUNCTION public.internal_list_integrations_by_org(uuid) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.internal_list_integrations_by_org(uuid) TO service_role;
COMMENT ON FUNCTION public.internal_list_integrations_by_org(uuid) IS
    'List integrations for an organization (bypasses RLS); service_role only; includes optional customer label';


-- Module: integration, File: 401_20260402_functions.sql
-- ---------------------------
-- MODULE NAME: integration
-- MODULE DATE: 20260402
-- MODULE SCOPE: functions
-- ---------------------------
-- Prefix 406: integration module functions band (106 tables, 206 indexes, 306 rlsgrants).
-- Server-side integration reads/updates that bypass RLS (service_role only).
-- Used by the API service client so programmatic and session flows behave consistently.
--
-- `internal_list_integrations_by_org` is defined in the customer module (`401_*_functions.sql`)
-- so it can join `integration_customers`. Do not redefine it here: MODULE_ORDER runs customer
-- before integration in the same scope tier, and PostgreSQL rejects CREATE OR REPLACE when
-- the RETURNS TABLE row shape would change.



CREATE OR REPLACE FUNCTION public.internal_get_integration_by_org_and_id(
    p_organization_id uuid,
    p_integration_id uuid
)
RETURNS SETOF public.integrations
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
STABLE
AS $$
    SELECT i.*
    FROM public.integrations i
    WHERE i.organization_id = p_organization_id
      AND i.id = p_integration_id
      AND i.deleted_at IS NULL
    LIMIT 1;
$$;

REVOKE ALL ON FUNCTION public.internal_get_integration_by_org_and_id(uuid, uuid) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.internal_get_integration_by_org_and_id(uuid, uuid) TO service_role;
COMMENT ON FUNCTION public.internal_get_integration_by_org_and_id(uuid, uuid) IS
    'Fetch one integration by organization and id (bypasses RLS); service_role only';

CREATE OR REPLACE FUNCTION public.internal_soft_delete_integration(
    p_organization_id uuid,
    p_integration_id uuid,
    p_new_internal_id text
)
RETURNS boolean
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
    UPDATE public.integrations
    SET
        internal_id = left(p_new_internal_id, 512),
        deleted_at = now(),
        updated_at = now()
    WHERE organization_id = p_organization_id
      AND id = p_integration_id
      AND deleted_at IS NULL;
    RETURN FOUND;
END;
$$;

REVOKE ALL ON FUNCTION public.internal_soft_delete_integration(uuid, uuid, text) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.internal_soft_delete_integration(uuid, uuid, text) TO service_role;
COMMENT ON FUNCTION public.internal_soft_delete_integration(uuid, uuid, text) IS
    'Soft-delete an integration row (bypasses RLS); service_role only';


